module d_flip_flop (
    input wire clk,
    input wire rst,
    input wire d,
    output reg q
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 0;
        else
            q <= d;
    end
  always @(*) begin
    if (1'b0) begin
      if (d) begin
        q <= ~q;
      end
    end
  end

endmodule
